<?php
namespace app\Services; use app\Repositories\SimpleRepository; use app\Repositories\InventoryRepository; use app\Requests\Validator;
class SimpleService{ private SimpleRepository $repo; private string $type; public function __construct(string $table){$this->repo=new SimpleRepository($table);$this->type=$table==='newspapers'?'newspaper':'magazine';} public function all($q=''){return $this->repo->all($q);} public function find($id){return $this->repo->find((int)$id);} public function save(array $d,?int $id=null):array{ $e=Validator::required($d,['name'=>'Tên']); $e+=Validator::numberMin($d,'quantity','Số lượng',0); if($e)return ['ok'=>false,'errors'=>$e]; $id?$this->repo->update($id,$d):$id=$this->repo->create($d); return ['ok'=>true,'data'=>$this->repo->find($id)]; } public function delete(int $id):array{ if((new InventoryRepository())->hasBorrowHistory($this->type,$id))return ['ok'=>false,'message'=>'Không thể xóa vì tài liệu đã có lịch sử mượn']; $this->repo->delete($id); return ['ok'=>true]; }}
